import React, { useEffect, useState } from 'react';
import { getAllOrders, updateOrderStatus } from '../../../services/orderService';
import toast from 'react-hot-toast';

const Orders = () => {

  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadOrders();
  }, []);

  const loadOrders = async () => {
    try {
      setLoading(true);
      const res = await getAllOrders();
      setOrders(res.data || []);
    } catch (err) {
      toast.error('Failed to load orders');
    } finally {
      setLoading(false);
    }
  };

  const changeStatus = async (id, status) => {
    try {
      await updateOrderStatus(id, { status });
      toast.success('Order updated');
      loadOrders();
    } catch (err) {
      toast.error('Failed to update order');
    }
  };

  return (
    <div>
      <h1>Manage Orders</h1>

      <div className="card mt-2">
        {loading ? (
          <div className="loader" />
        ) : (
          <div style={{overflowX: 'auto'}}>
            <table style={{width: '100%', borderCollapse: 'collapse'}}>
              <thead>
                <tr>
                  <th style={{textAlign: 'left', padding: '8px'}}>Order ID</th>
                  <th style={{padding: '8px'}}>User</th>
                  <th style={{padding: '8px'}}>Total</th>
                  <th style={{padding: '8px'}}>Status</th>
                  <th style={{padding: '8px'}}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {orders.map(o => (
                  <tr key={o._id} style={{borderTop: '1px solid #eee'}}>
                    <td style={{padding: '10px'}}>{o._id}</td>
                    <td style={{padding: '10px', textAlign: 'center'}}>{o.user?.name || o.user || '-'}</td>
                    <td style={{padding: '10px', textAlign: 'center'}}>₹{o.totalPrice ?? o.total ?? '-'}</td>
                    <td style={{padding: '10px', textAlign: 'center'}}>{o.status || 'Pending'}</td>
                    <td style={{padding: '10px', textAlign: 'center'}}>
                      <select value={o.status || 'Pending'} onChange={(e) => changeStatus(o._id, e.target.value)}>
                        <option value="Pending">Pending</option>
                        <option value="Processing">Processing</option>
                        <option value="Shipped">Shipped</option>
                        <option value="Delivered">Delivered</option>
                        <option value="Cancelled">Cancelled</option>
                      </select>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default Orders;
